import logging
import traceback
import uuid
from functools import wraps

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class ErrorLogger:
 @staticmethod
 def log_exception(exc_type, exc_value, exc_traceback, context=None):
 if issubclass(exc_type, KeyboardInterrupt):
 raise exc_type(exc_value)

 error_id = str(uuid.uuid4())
 logger.error(
 f"Error ID: {error_id}",
 extra={
 'error_type': exc_type.__name__,
 'error_message': str(exc_value),
 'traceback': traceback.format_exception(exc_type, exc_value, exc_traceback),
 'context': context or {}
 }
 )
 return error_id

# Usage with decorator
def log_errors(context=''):
 def decorator(func):
 @wraps(func)
 def wrapper(*args, **kwargs):
 try:
 return func(*args, **kwargs)
 except Exception as e:
 error_id = ErrorLogger.log_exception(
 type(e), e, e.__traceback__,
 {'function': func.__name__, 'context': context}
 )
 print(f"Error logged. ID: {error_id}")
 raise
 return wrapper
 return decorator

@log_errors(context='user_authentication')
def authenticate(username):
 if not username:
 raise ValueError("Username cannot be empty")
 return True
